import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { arm, clearStudioMapping, disarm, isArmed, isBitfabMcpToolName, listArmedSessionIds, readArmedMetadata, readStudioMapping, writeStudioMapping, } from "./arming.js";
describe("isBitfabMcpToolName", () => {
    it("matches the long Claude plugin prefix", () => {
        expect(isBitfabMcpToolName("mcp__plugin_bitfab_Bitfab__list_trace_functions")).toBe(true);
    });
    it("matches the short Cursor/Codex prefix", () => {
        expect(isBitfabMcpToolName("mcp__Bitfab__read_traces")).toBe(true);
    });
    it("does not match other MCP servers", () => {
        expect(isBitfabMcpToolName("mcp__plugin_other_Server__do_thing")).toBe(false);
        expect(isBitfabMcpToolName("Read")).toBe(false);
    });
});
describe("arm/isArmed/disarm", () => {
    let tempHome;
    const originalHome = process.env.HOME;
    const sessionId = "session-arming-test";
    const meta = {
        transcriptPath: "/tmp/fake-transcript.jsonl",
        cwd: "/tmp/fake-cwd",
        agent: "claude-code",
    };
    beforeEach(() => {
        tempHome = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-arming-"));
        process.env.HOME = tempHome;
    });
    afterEach(() => {
        process.env.HOME = originalHome;
        fs.rmSync(tempHome, { recursive: true, force: true });
    });
    it("starts unarmed and arms when called", () => {
        expect(isArmed(sessionId)).toBe(false);
        arm(sessionId, meta);
        expect(isArmed(sessionId)).toBe(true);
    });
    it("disarm removes the marker", () => {
        arm(sessionId, meta);
        disarm(sessionId);
        expect(isArmed(sessionId)).toBe(false);
    });
    it("arming twice is idempotent", () => {
        arm(sessionId, meta);
        arm(sessionId, meta);
        expect(isArmed(sessionId)).toBe(true);
    });
    it("stores and reads metadata", () => {
        arm(sessionId, meta);
        const read = readArmedMetadata(sessionId);
        expect(read).toEqual(meta);
    });
    it("readArmedMetadata returns null for empty marker files", () => {
        arm(sessionId, meta);
        fs.writeFileSync(path.join(tempHome, ".config", "bitfab", "sessions", `${sessionId}.armed`), "");
        expect(readArmedMetadata(sessionId)).toBeNull();
    });
    it("listArmedSessionIds returns armed session ids", () => {
        arm("session-a", meta);
        arm("session-b", meta);
        const ids = listArmedSessionIds();
        expect(ids.sort()).toEqual(["session-a", "session-b"]);
    });
});
describe("writeStudioMapping/readStudioMapping/clearStudioMapping", () => {
    let tempHome;
    const originalHome = process.env.HOME;
    const agentSessionId = "agent-session-123";
    const studioSessionId = "studio-session-456";
    beforeEach(() => {
        tempHome = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-studio-map-"));
        process.env.HOME = tempHome;
    });
    afterEach(() => {
        process.env.HOME = originalHome;
        fs.rmSync(tempHome, { recursive: true, force: true });
    });
    it("returns null when no mapping exists", () => {
        expect(readStudioMapping(agentSessionId)).toBeNull();
    });
    it("writes and reads a mapping", () => {
        writeStudioMapping(agentSessionId, studioSessionId);
        const mapping = readStudioMapping(agentSessionId);
        expect(mapping).not.toBeNull();
        expect(mapping.studioSessionId).toBe(studioSessionId);
        expect(typeof mapping.createdAt).toBe("string");
    });
    it("clearStudioMapping removes the mapping", () => {
        writeStudioMapping(agentSessionId, studioSessionId);
        expect(readStudioMapping(agentSessionId)).not.toBeNull();
        clearStudioMapping(agentSessionId);
        expect(readStudioMapping(agentSessionId)).toBeNull();
    });
    it("clearStudioMapping is safe on missing mapping", () => {
        expect(() => clearStudioMapping("nonexistent")).not.toThrow();
    });
    it("readStudioMapping returns null for empty file", () => {
        writeStudioMapping(agentSessionId, studioSessionId);
        const filePath = path.join(tempHome, ".config", "bitfab", "sessions", `${agentSessionId}.studio`);
        fs.writeFileSync(filePath, "");
        expect(readStudioMapping(agentSessionId)).toBeNull();
    });
    it("readStudioMapping returns null for malformed JSON", () => {
        writeStudioMapping(agentSessionId, studioSessionId);
        const filePath = path.join(tempHome, ".config", "bitfab", "sessions", `${agentSessionId}.studio`);
        fs.writeFileSync(filePath, "not-json");
        expect(readStudioMapping(agentSessionId)).toBeNull();
    });
    it("supports multiple concurrent mappings", () => {
        writeStudioMapping("agent-1", "studio-a");
        writeStudioMapping("agent-2", "studio-b");
        expect(readStudioMapping("agent-1").studioSessionId).toBe("studio-a");
        expect(readStudioMapping("agent-2").studioSessionId).toBe("studio-b");
    });
});
